import { defineAgent } from 'eve'

export default defineAgent({
  model: 'anthropic/claude-haiku-4-5',
})

[
  {
    "name": "getPlanetaryData",
    "signature": "getPlanetaryData(planet: string): Promise<PlanetaryData>",
    "description": "Fetches orbital and physical data for a planet in the solar system.",
    "parameters": [
      { "name": "planet", "type": "string", "description": "Planet name, e.g. \"mars\"." }
    ],
    "example": "const data = await getPlanetaryData('mars')"
  },
  {
    "name": "computeOrbit",
    "signature": "computeOrbit(body: string, days: number): Orbit",
    "description": "Computes the projected orbit of a body over a number of days.",
    "parameters": [
      { "name": "body", "type": "string", "description": "Body identifier." },
      { "name": "days", "type": "number", "description": "Projection window in days." }
    ],
    "example": "const orbit = computeOrbit('halley', 365)"
  }
]

import { readFile } from 'node:fs/promises'
import { fileURLToPath } from 'node:url'
import { defineTool } from 'eve/tools'
import { never } from 'eve/tools/approval'
import { z } from 'zod'

interface FunctionDoc {
  name: string
  signature: string
  description: string
}

const DATA_URL = new URL('../data/functions.json', import.meta.url)

export default defineTool({
  needsApproval: never(),
  description:
    'Looks up library functions matching a name or keyword and returns their documentation.',
  inputSchema: z.object({
    query: z.string(),
  }),
  async execute({ query }) {
    const docs = JSON.parse(
      await readFile(fileURLToPath(DATA_URL), 'utf-8')
    ) as FunctionDoc[]
    const q = query.toLowerCase()
    const matches = docs.filter(
      (d) =>
        d.name.toLowerCase().includes(q) ||
        d.description.toLowerCase().includes(q)
    )
    return matches.length
      ? { matches }
      : { suggestions: docs.map((d) => d.name) }
  },
})
